class Solution(object):
    def threeSumMulti(self, arr, target):
        from collections import Counter
        freq = Counter(arr)
        result = 0
        MOD = 10**9 + 7
        for i in freq:
            for j in freq:
                k = target - i - j
                if k < i or k not in freq:
                    continue
                if i == j == k:
                    result += freq[i] * (freq[i] - 1) * (freq[i] - 2) // 6
                elif i == j < k:
                    result += freq[i] * (freq[i] - 1) // 2 * freq[k]
                elif i < j == k:
                    result += freq[i] * freq[j] * (freq[j] - 1) // 2
                elif i < j < k:
                    result += freq[i] * freq[j] * freq[k]
                result %= MOD
        return result
